    __global__ void DecomposeKernelHardcoded(
        double* __restrict__ d_ALU_base,
        uint32_t number_of_grid_cells,
        uint32_t vector_length,
        uint32_t nnz)
    {
      uint32_t tid = blockIdx.x * BLOCK_SIZE + threadIdx.x;
      if (tid >= number_of_grid_cells)
        return;

      const uint32_t vl = vector_length;
      const uint32_t local_tid = tid % vl;
      const uint32_t group_id = tid / vl;
      double* d_ALU = d_ALU_base + group_id * static_cast<uint64_t>(nnz) * vl;

      uint32_t aji_pos = 0;
      uint32_t aik_pos = 0;
      uint32_t ajk_pos = 0;

      for (uint32_t i = 0; i < N; ++i)
      {
        const double Aii_inverse = 1.0 / d_ALU[hc_aii[i] + local_tid];

        const uint32_t nji = hc_nji[i];
#pragma unroll
        for (uint32_t ij = 0; ij < nji; ++ij)
        {
          d_ALU[hc_aji[aji_pos + ij] + local_tid] *= Aii_inverse;
        }
        aji_pos += nji;

        const uint32_t nki = hc_nki[i];
        for (uint32_t ik = 0; ik < nki; ++ik)
        {
          const uint32_t aik_idx = hc_aik_njk_packed[(aik_pos + ik) * 2];
          const uint32_t njk = hc_aik_njk_packed[(aik_pos + ik) * 2 + 1];
          const double Aik = d_ALU[aik_idx + local_tid];

#pragma unroll
          for (uint32_t ijk = 0; ijk < njk; ++ijk)
          {
            const uint32_t ajk_idx = hc_ajk_aji_packed[(ajk_pos + ijk) * 2];
            const uint32_t aji_idx = hc_ajk_aji_packed[(ajk_pos + ijk) * 2 + 1];
            d_ALU[ajk_idx + local_tid] -= d_ALU[aji_idx + local_tid] * Aik;
          }
          ajk_pos += njk;
        }
        aik_pos += nki;
      }
    }

    void DecomposeKernelHardcodedDriver(CudaMatrixParam& ALU_param, uint32_t number_of_non_zeros)
    {
      std::size_t num_cells = ALU_param.number_of_grid_cells_;
      std::size_t num_blocks = (num_cells + BLOCK_SIZE - 1) / BLOCK_SIZE;
      auto stream = micm::cuda::CudaStreamSingleton::GetInstance().GetCudaStream(0);

      DecomposeKernelHardcoded<<<num_blocks, BLOCK_SIZE, 0, stream>>>(
          ALU_param.d_data_,
          static_cast<uint32_t>(num_cells),
          static_cast<uint32_t>(ALU_param.vector_length_),
          number_of_non_zeros);
    }
